parameters.jsCode:
const input = $input.first().json;

let events = null;

if (input.events && Array.isArray(input.events)) {
  events = input.events;
} else if (input.body && input.body.events && Array.isArray(input.body.events)) {
  events = input.body.events;
}

if (!events || events.length === 0) {
  return [{ json: { skip: true, userId: '', replyToken: '', messageText: '', eventType: '' } }];
}

const event = events[0];
const userId = event.source?.userId || '';
const replyToken = event.replyToken || '';
const messageText = event.message?.text || '';
const eventType = event.type || '';

if (eventType !== 'message' || event.message?.type !== 'text') {
  return [{ json: { skip: true, userId, replyToken, messageText: '', eventType } }];
}

return [{
  json: {
    skip: false,
    userId,
    replyToken,
    messageText,
    eventType
  }
}];

const lineEvent = $('Parse LINE event').first().json;
const config = $('Set config').first().json;

return [{
  json: {
    userId: lineEvent.userId,
    replyToken: lineEvent.replyToken,
    messageText: lineEvent.messageText,
    SHEET_ID: config.SHEET_ID,
    HISTORY_SHEET_NAME: config.HISTORY_SHEET_NAME,
    LINE_CHANNEL_ACCESS_TOKEN: config.LINE_CHANNEL_ACCESS_TOKEN
  }
}];

const rawText = $input.first().json.text || '';
const prevData = $('Build context').first().json;

const jsonMatch = rawText.match(/\{[\s\S]*\}/);
let advice = {
  fortune_teller: 'No message received from the Fortune Teller.',
  business_coach: 'No message received from the Business Coach.',
  best_friend: 'No message received from the Best Friend.'
};

if (jsonMatch) {
  try {
    advice = JSON.parse(jsonMatch[0]);
  } catch(e) {
    // use defaults on parse failure
  }
}

return [{
  json: {
    userId: prevData.userId,
    replyToken: prevData.replyToken,
    messageText: prevData.messageText,
    fortune_teller: advice.fortune_teller || 'No message received from the Fortune Teller.',
    business_coach: advice.business_coach || 'No message received from the Business Coach.',
    best_friend: advice.best_friend || 'No message received from the Best Friend.',
    SHEET_ID: prevData.SHEET_ID,
    HISTORY_SHEET_NAME: prevData.HISTORY_SHEET_NAME,
    LINE_CHANNEL_ACCESS_TOKEN: prevData.LINE_CHANNEL_ACCESS_TOKEN
  }
}];

